import React, { useState, useMemo } from 'react';
import { Button, Input, Select, Modal, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { masterService } from '../../../services/master/masterService';
import type { ExchangeRateDto, CurrencyDto } from '../../../services/master/models';
import { formatNumber } from '../../../utils/formatters';
import { normalizeCode } from '../../../utils/codeField';
import { scrollToFirstFieldError } from '../../../utils/catalogFormValidation';
import { CatalogCompanyTh, CatalogCompanyTd, CatalogCompanyField } from '../../../components/catalog';
import { useCompanyLabelMap } from '../../../hooks/useCompanyLabelMap';
import styles from '../../../styles/erpPage.module.css';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';
import { selectPlaceholderClass } from '../../../utils/selectField';

const TEST_ID = 'dm-ty-gia';

type FormErrors = Partial<Record<'currencyCode' | 'monthYear' | 'buyRate' | 'transferRate', string>>;

const TyGiaPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { sessionCompanyId } = useCompanyLabelMap();
  const [currencyFilter, setCurrencyFilter] = useState('');
  const [currencies, setCurrencies] = useState<CurrencyDto[]>([]);
  const [items, setItems] = useState<ExchangeRateDto[]>([]);
  const [loading, setLoading] = useState(false);
  const [modalOpen, setModalOpen] = useState(false);
  const [form, setForm] = useState<{ currencyCode: string; monthYear: string; buyRate: string; sellRate: string; transferRate: string }>({
    currencyCode: '', monthYear: '', buyRate: '', sellRate: '', transferRate: '',
  });
  const [errors, setErrors] = useState<FormErrors>({});
  const [saving, setSaving] = useState(false);
  const [deleteId, setDeleteId] = useState<string | null>(null);
  const [reloadKey, setReloadKey] = useState(0);
  const handleSearch = () => setReloadKey(k => k + 1);
  const refresh = () => setReloadKey(k => k + 1);

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      masterService.getCurrencies({ page: 1, pageSize: 500 })
        .then(data => { if (!cancelled) setCurrencies(data.items); })
        .catch(() => { /* optional */ });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, []);

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      masterService.getExchangeRates({ currencyCode: currencyFilter || undefined })
        .then(data => { if (!cancelled) setItems(data); })
        .catch(err => {
          if (!cancelled) dispatch(addToast({ message: err?.message ?? 'Lỗi tải tỷ giá', type: 'error' }));
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [currencyFilter, reloadKey, dispatch]);

  const currencyOpts = useMemo(
    () => currencies.map(c => ({ value: c.code, label: `${c.code} — ${c.name}` })),
    [currencies],
  );

  const modalCurrencyOpts = currencyOpts;

  const clearFieldError = (key: keyof FormErrors) => {
    setErrors(prev => {
      if (!prev[key]) return prev;
      const next = { ...prev };
      delete next[key];
      return next;
    });
  };

  const validate = (): FormErrors => {
    const next: FormErrors = {};
    if (!form.currencyCode?.trim()) next.currencyCode = 'Chọn ngoại tệ';
    if (!form.monthYear?.trim()) next.monthYear = 'Chọn tháng/năm';
    if (!form.buyRate?.trim()) next.buyRate = 'Nhập tỷ giá mua vào';
    if (!form.transferRate?.trim()) next.transferRate = 'Nhập tỷ giá chuyển khoản';
    return next;
  };

  const openAdd = () => {
    setForm({
      currencyCode: currencyFilter || currencies[0]?.code || '',
      monthYear: new Date().toISOString().slice(0, 7),
      buyRate: '',
      sellRate: '',
      transferRate: '',
    });
    setErrors({});
    setModalOpen(true);
  };

  const handleSave = async () => {
    const nextErrors = validate();
    if (Object.keys(nextErrors).length > 0) {
      setErrors(nextErrors);
      scrollToFirstFieldError(TEST_ID);
      return;
    }
    const [yearStr, monthStr] = form.monthYear.split('-');
    const month = Number(monthStr);
    const year = Number(yearStr);
    setSaving(true);
    try {
      await masterService.createExchangeRate({
        currencyCode: normalizeCode(form.currencyCode),
        month,
        year,
        buyRate: Number(form.buyRate),
        sellRate: form.sellRate ? Number(form.sellRate) : undefined,
        transferRate: Number(form.transferRate),
      });
      dispatch(addToast({ message: 'Tạo tỷ giá thành công', type: 'success' }));
      setModalOpen(false);
      setReloadKey(k => k + 1);
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Lưu thất bại', type: 'error' }));
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (id: string) => {
    try {
      await masterService.deleteExchangeRate(id);
      dispatch(addToast({ message: 'Xóa tỷ giá thành công', type: 'success' }));
      setDeleteId(null);
      setReloadKey(k => k + 1);
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Xóa thất bại', type: 'error' }));
    }
  };

  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}>
        <div className={styles.titleBlock}>
          <h1 className={styles.title}><i className="fas fa-exchange-alt" /> Tỷ giá ngoại tệ</h1>
        </div>
        <div className={styles.headerActions}>
          <Button variant="primary" onClick={openAdd} data-testid={`${TEST_ID}-add-btn`}>
            <i className="fas fa-plus" /> Thêm tỷ giá
          </Button>
        </div>
      </div>

      <div className={styles.filtersBar} data-testid={`${TEST_ID}-filters`}>
        <div className={styles.field} data-testid={`${TEST_ID}-field-currencyFilter`}>
          <Select
            value={currencyFilter}
            placeholder="Tất cả ngoại tệ"
            className={selectPlaceholderClass(currencyFilter)}
            onChange={e => setCurrencyFilter(e.target.value)}
            options={currencyOpts}
          />
        </div>
        <ListSearchRefreshButtons testIdPrefix={TEST_ID} onSearch={handleSearch} onRefresh={refresh} showSearch={false} />
      </div>

      <div className={styles.tableCard}>
        {loading ? (
          <div className={styles.loading}><i className="fas fa-spinner fa-spin" /> Đang tải...</div>
        ) : items.length === 0 ? (
          <div className={styles.empty}><i className="fas fa-inbox" /><p>Không có dữ liệu</p></div>
        ) : (
          <div className={styles.tableWrapper}>
            <table className={styles.table}>
              <thead>
                <tr>
                  <th>Ngoại tệ</th>
                  <th>Tháng/Năm</th>
                  <th className={styles.colRight}>Mua vào</th>
                  <th className={styles.colRight}>Bán ra</th>
                  <th className={styles.colRight}>Chuyển khoản</th>
                  <th className={styles.colActions} />
                </tr>
              </thead>
              <tbody>
                {items.map(r => (
                  <tr key={r.id}>
                    <td><code>{r.currencyCode}</code></td>
                    <td>{r.month}/{r.year}</td>
                    <td className={styles.colRight}>{formatNumber(r.buyRate)}</td>
                    <td className={styles.colRight}>{formatNumber(r.sellRate)}</td>
                    <td className={styles.colRight}>{formatNumber(r.transferRate)}</td>
                    <td className={styles.colActions}>
                      <button type="button" className={`${styles.actionBtn} ${styles.actionBtnDanger}`} onClick={() => setDeleteId(r.id)} title="Xóa">
                        <i className="fas fa-trash" />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      <Modal isOpen={modalOpen} onClose={() => setModalOpen(false)} title="Thêm tỷ giá">
        <div className={styles.modalBody} data-testid={`${TEST_ID}-form`}>
          <div className={styles.formGrid}>
            <div className={styles.field} data-testid={`${TEST_ID}-field-currencyCode`}>
              <label className={styles.label}>Ngoại tệ *</label>
              <Select
                value={form.currencyCode}
                required
                placeholder="— Chọn ngoại tệ —"
                className={selectPlaceholderClass(form.currencyCode)}
                error={errors.currencyCode}
                onChange={e => {
                  clearFieldError('currencyCode');
                  setForm(f => ({ ...f, currencyCode: normalizeCode(e.target.value) }));
                }}
                options={modalCurrencyOpts}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-monthYear`}>
              <label className={styles.label}>Tháng/Năm *</label>
              <Input
                type="month"
                value={form.monthYear}
                error={errors.monthYear}
                onChange={e => {
                  clearFieldError('monthYear');
                  setForm(f => ({ ...f, monthYear: e.target.value }));
                }}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-buyRate`}>
              <label className={styles.label}>Tỷ giá mua vào *</label>
              <Input
                type="number"
                value={form.buyRate}
                error={errors.buyRate}
                onChange={e => {
                  clearFieldError('buyRate');
                  setForm(f => ({ ...f, buyRate: e.target.value }));
                }}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-sellRate`}>
              <label className={styles.label}>Tỷ giá bán ra</label>
              <Input type="number" value={form.sellRate} onChange={e => setForm(f => ({ ...f, sellRate: e.target.value }))} />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-transferRate`}>
              <label className={styles.label}>Tỷ giá chuyển khoản *</label>
              <Input
                type="number"
                value={form.transferRate}
                error={errors.transferRate}
                onChange={e => {
                  clearFieldError('transferRate');
                  setForm(f => ({ ...f, transferRate: e.target.value }));
                }}
              />
            </div>
          </div>
          <CatalogCompanyField
            testIdPrefix={TEST_ID}
            companyId={sessionCompanyId}
          />
          <div className={styles.modalActions}>
            <Button variant="secondary" onClick={() => setModalOpen(false)}>Hủy</Button>
            <Button variant="primary" onClick={handleSave} disabled={saving} data-testid={`${TEST_ID}-save-btn`}>
              {saving ? 'Đang lưu...' : 'Lưu'}
            </Button>
          </div>
        </div>
      </Modal>

      <Modal isOpen={deleteId != null} onClose={() => setDeleteId(null)} title="Xác nhận xóa">
        <p>Bạn có chắc muốn xóa tỷ giá này?</p>
        <div className={styles.modalActions}>
          <Button variant="secondary" onClick={() => setDeleteId(null)}>Hủy</Button>
          <Button variant="primary" onClick={() => deleteId != null && handleDelete(deleteId)}>Xóa</Button>
        </div>
      </Modal>
    </div>
  );
};

export default TyGiaPage;
